1516	        return rbtdre_Verdict::Fail(format!("{}: write Dockerfile failed: {}", label, e));
1517	    }
1518	    let path_str = dockerfile.to_string_lossy().into_owned();
1519	    let result = if expect_pass {
1520	        rbtdrf_run_tt(&root, RBTDGC_HYGIENE_CHECK_DOCKERFILE, &[&path_str], dir, label)
1521	    } else {
1522	        rbtdrf_run_tt_neg(&root, RBTDGC_HYGIENE_CHECK_DOCKERFILE, &[&path_str], dir, label)
1523	    };
1524	    match result {
1525	        Ok(()) => rbtdre_Verdict::Pass,
1526	        Err(e) => rbtdre_Verdict::Fail(e),
1527	    }
1528	}
